CREATE OR REPLACE VIEW vmb_transaction_dep (seq_no, transaction_no, transaction_type, from_bay_account_no, from_coop_account_no, from_coop_account_name, to_coop_account_no, to_bay_account_no, to_account_name, transaction_amount, transaction_fee, transaction_balance, channel, transaction_date, transaction_time) AS SELECT sc_dep_m_creditor_item.seq_no   AS SEQ_NO
         ,sc_dep_m_creditor_item.refer_to_deposit_doc_no  AS TRANSACTION_NO
         ,sc_dep_m_creditor_item.item_type                AS  TRANSACTION_TYPE
         ,'' AS FROM_BAY_ACCOUNT_NO
         ,trim(both sc_dep_m_creditor.deposit_account_no )      AS FROM_COOP_ACCOUNT_NO
         ,sc_dep_m_creditor.deposit_account_name          AS  FROM_COOP_ACCOUNT_NAME
         ,'' AS TO_COOP_ACCOUNT_NO
         ,'' AS TO_BAY_ACCOUNT_NO
         ,'' AS TO_ACCOUNT_NAME
         ,sc_dep_m_creditor_item.deposit_balance        AS TRANSACTION_AMOUNT
         ,0                                             AS TRANSACTION_FEE
         ,sc_dep_m_creditor_item.total_balance          AS TRANSACTION_BALANCE
         ,sc_com_m_branch.branch_name                   AS CHANNEL
         ,to_char( sc_dep_m_creditor_item.working_day,'yyyy-mm-dd')   AS TRANSACTION_DATE
         ,to_char(sc_dep_m_creditor_item.last_access_date,'dd/mm/yyyy HH24:MI:SS')     AS TRANSACTION_TIME
    FROM sc_dep_m_creditor_item
         ,sc_dep_m_creditor          
